const event = $('Execute Workflow Trigger').item.json;
const row = $json || {};
const safeObj = v => (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};
const safeArr = v => Array.isArray(v) ? v : [];

const kpis = safeObj(row.kpis);
const fases = safeObj(row.fases);
const github = safeObj(row.github);
const ranking = safeArr(row.ranking);
const stale = safeArr(row.cards_stale);
const problemas = safeArr(row.problemas_detectados);
const iaAnterior = String(row.recomendaciones_ia || '').slice(0, 500);

const diasFin = kpis.dias_hasta_fin || '?';
const velocidad = kpis.velocidad_tareas_por_dia || 0;
const completadas7d = kpis.completadas_7d || 0;
const silBack = kpis.silencio_back_dias || '-';
const silFront = kpis.silencio_front_dias || '-';
const busF = kpis.bus_factor_14d || 0;
const pctConv = kpis.pct_commits_convencionales || 0;
const prOpenTime = kpis.pr_open_time_dias || 0;
const prMergeRatio = kpis.pr_merge_ratio_30d || 0;

const fasesProblema = Object.values(fases)
  .filter(f => f.semaforo === 'rojo' || f.semaforo === 'amarillo' || f.vencidas > 0)
  .map(f => `${f.nombre}: ${f.pct}% (${f.vencidas} vencidas, ${f.pendientes} pendientes)`)
  .join('; ') || 'Ninguna fase en alerta';

const rankingStr = ranking.slice(0, 5)
  .map(r => `${r.trello_name}: done=${r.tareas_done}, pending=${r.tareas_pending}, overdue=${r.tareas_overdue}, commits14d=${r.commits_14d}`)
  .join(' | ') || 'Sin datos de equipo';

const problemasStr = problemas
  .map(p => `${p.tipo} (sev=${p.severidad}${p.count ? ', count='+p.count : ''})`)
  .join(', ') || 'Ninguno detectado';

const staleStr = stale.slice(0, 5)
  .map(t => `${t.nombre} (${t.dias_sin_actividad}d sin actividad, resp: ${(t.responsables || ['?'])[0] || 'sin asignar'})`)
  .join(', ') || 'Ninguna';

const ciBack = github.ci_back ? `${github.ci_back.status} en ${github.ci_back.branch}` : 'sin datos';
const ciFront = github.ci_front ? `${github.ci_front.status} en ${github.ci_front.branch}` : 'sin datos';

const errores14d = Number(row.errores_14d || 0);
const avgCycleH = Number(row.avg_cycle_hours || 0).toFixed(1);
const diagnosticos30d = Number(row.diagnosticos_30d || 0);

const triggerMode = String(event.trigger_mode || 'retro').toLowerCase();
const isCiFailure = triggerMode === 'postmortem' || String(event.event_type || '').includes('ci_fail');

let misionText;
if (isCiFailure) {
  misionText = `Se ha detectado un fallo tecnico (${event.event_type || 'CI fallido'}). Actua como facilitador de POST-MORTEM: analiza la causa raiz probable (sin inventar, usa los datos), el impacto en el proyecto y redacta un documento de acciones correctivas.\nEstructura obligatoria:\nQUE PASO: Descripcion objetiva del incidente.\nCAUSA RAIZ: Hipotesis basada en datos (CI, commits, PRs, actividad del equipo).\nIMPACTO: Dias de retraso estimados o tareas afectadas.\nACCIONES CORRECTIVAS: Minimo 3, asignadas por nombre real del equipo (FG, DM, DP, JA).\nMEDIDA PREVENTIVA: Como evitar que se repita.`;
} else {
  misionText = `Actua como Agile Coach: facilita una retrospectiva basada en datos reales del ultimo periodo. Proporciona insights de mejora continua accionables.\nEstructura obligatoria:\nQUE SALIO BIEN: 2-3 aspectos positivos con datos que los respalden.\nQUE SALIO MAL: 2-3 problemas reales identificados con datos.\nQUE MEJORAR: 3 acciones especificas, asignadas por nombre (FG=Felipe Guerrero, DM=David Mendez, DP=David Perez, JA=Josue Asencio).\nEXPERIMENTO SPRINT SIGUIENTE: Una mejora concreta y medible para probar la proxima semana.\nSEMAFORO DE SALUD: verde/amarillo/rojo con justificacion numerica de una oracion.`;
}

const prompt = `Eres el Agile Coach del proyecto PetSafe (clinica veterinaria, NestJS+Angular, cierre 10-jun-2026). Usa datos reales, texto plano, SIN markdown, SIN asteriscos, en espanol.\n\nDATA PERIODO ACTUAL\nProgreso: ${row.progreso_pct}% (${row.total_completadas}/${row.total_tarjetas})\nDias hasta cierre: ${diasFin} | Velocidad: ${velocidad} tareas/dia | Completadas 7d: ${completadas7d}\nSilencio back: ${silBack}d | front: ${silFront}d\nBus factor 14d: ${busF} | Commits convencionales: ${pctConv}%\nPRs: avg ${prOpenTime}d abierto | merge ratio ${prMergeRatio}%\nCI Backend: ${ciBack} | CI Frontend: ${ciFront}\nErrores de sistema 14d: ${errores14d} | Ciclo promedio: ${avgCycleH}h\nDiagnosticos IA 30d: ${diagnosticos30d}\n\nFASES CON PROBLEMAS: ${fasesProblema}\nCARDS STALE: ${staleStr}\nPROBLEMAS DETECTADOS: ${problemasStr}\nCARGA EQUIPO: ${rankingStr}\nNOTAS PREVIAS PM: ${iaAnterior}\n\n${misionText}`;

return [{ json: {
  correlation_id: event.correlation_id || `agile-${Date.now()}`,
  event_type: event.event_type || 'retrospectiva',
  actor: event.actor || 'system',
  trigger_mode: isCiFailure ? 'postmortem' : 'retro',
  prompt
}}];

const raw = $json.text ?? $json.output ?? $json.response ?? '';
const retroText = typeof raw === 'string' ? raw.trim() : JSON.stringify(raw);
const ctx = $('Prepare Retro Context').item.json;
const isPostmortem = ctx.trigger_mode === 'postmortem';
const title = isPostmortem ? '🚨 Post-Mortem PetSafe' : '🔄 Retrospectiva PetSafe';
const desc = isPostmortem ? 'Analisis de causa raiz y acciones correctivas.' : 'Reflexion agil del periodo con mejoras accionables.';
const color = isPostmortem ? 15158332 : 3066993;
const discord_payload = {
  username: 'PM PetSafe · Agile Coach',
  embeds: [{
    title,
    description: desc,
    color,
    fields: [{ name: isPostmortem ? '📋 Análisis Post-Mortem' : '📋 Retrospectiva', value: retroText.slice(0, 1024) }],
    footer: { text: `Agile Coach · ${ctx.trigger_mode} · PM PetSafe AI` },
    timestamp: new Date().toISOString()
  }],
  allowed_mentions: { parse: [] }
};
const chunkSize = 1024;
if (retroText.length > chunkSize) {
  const extra = retroText.slice(chunkSize, chunkSize * 3);
  if (extra) discord_payload.embeds[0].fields.push({ name: '📋 (continuación)', value: extra.slice(0, 1024) });
}
return [{ json: {
  correlation_id: ctx.correlation_id,
  agent_role: 'Agile Coach',
  decision_type: ctx.trigger_mode,
  input_summary: `${ctx.trigger_mode}: event=${ctx.event_type}`.slice(0,500),
  context_used: { trigger_mode: ctx.trigger_mode, event_type: ctx.event_type },
  evidence: { retro_text: retroText.slice(0,1000) },
  decision: { retro: retroText.slice(0,500) },
  recommendation: retroText.slice(0,500),
  confidence: 0.85,
  risk_level: isPostmortem ? 'high' : 'medium',
  requires_human_approval: isPostmortem,
  discord_payload
}}];
